1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const COMPONENT_PREMIUM = 25;
25	const COMPONENT_BLOCK_SIZE = 3;
26	const COMPONENT_BLOCK_PREMIUM = 60;
27	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
28	
29	const FIRST_INSURANCE_SURCHARGE = 1.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const LOYALTY_THRESHOLD_YEARS = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const PROCESSING_FEE = 5;
36	
37	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
38	
39	const sum = (values: number[]): number => values.reduce((acc, value) => acc + value, 0);
40	
41	// Base premium of a single item (main item or one component).
42	const itemBase = (item: Item): number =>
43	  isComponent(item) ? COMPONENT_PREMIUM : (BASE_PREMIUM[item.type] ?? 0);
44	
45	// A surcharge adds `rate` of the base premium for each affected item.
46	const surchargeFor = (items: Item[], affects: (item: Item) => boolean, rate: number): number =>
47	  sum(items.filter(affects).map((item) => rate * itemBase(item)));
48	
49	// Curse adds 50% of the affected item's base premium.
50	const curseSurcharge = (items: Item[]): number =>
51	  surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
52	
53	// High enchantment (level >= 5) adds 30% of the affected item's base premium.
54	const enchantmentSurcharge = (items: Item[]): number =>
55	  surchargeFor(
56	    items,
57	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
58	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
59	  );
60	
61	// Base premium for `count` alike components: a group of exactly 3 forms a
62	// block at COMPONENT_BLOCK_PREMIUM; otherwise each component costs
63	// COMPONENT_PREMIUM.
64	const componentGroupPremium = (count: number): number =>
65	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
66	
67	// Count how many alike components of each type appear (e.g. { rune: 2 }).
68	const countByType = (items: Item[]): Map<string, number> =>
69	  items.reduce((counts, item) => {
70	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
71	    return counts;
72	  }, new Map<string, number>());
73	
74	const mainItemsPremium = (items: Item[]): number =>
75	  sum(items.filter((item) => !isComponent(item)).map(itemBase));
76	
77	const componentsPremium = (items: Item[]): number =>
78	  sum([...countByType(items.filter(isComponent)).values()].map(componentGroupPremium));
79	
80	const basePremium = (items: Item[]): number =>
81	  mainItemsPremium(items) + componentsPremium(items);
82	
83	// Round up to a whole number in MHPCO's favour, guarding against
84	// floating-point noise (e.g. 197.5000000001) before the ceiling by snapping
85	// to 6 decimal places first.
86	const FLOAT_GUARD_PRECISION = 1e6;
87	const roundUpToWhole = (value: number): number =>
88	  Math.ceil(Math.round(value * FLOAT_GUARD_PRECISION) / FLOAT_GUARD_PRECISION);
89	
90	// Long-standing customers (>= 2 years) receive 20% off the policy base.
91	const loyaltyDiscount = (items: Item[], yearsWithMHPCO: number): number =>
92	  yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? LOYALTY_DISCOUNT_RATE * basePremium(items) : 0;
93	
94	// Premium for one quote: base premium plus the first-insurance surcharge,
95	// item-specific curse/enchantment surcharges, less the loyalty discount,
96	// and the flat processing fee.
97	const quotePremium = (items: Item[], yearsWithMHPCO: number): number =>
98	  basePremium(items) * FIRST_INSURANCE_SURCHARGE +
99	  curseSurcharge(items) +
100	  enchantmentSurcharge(items) -
101	  loyaltyDiscount(items, yearsWithMHPCO) +
102	  PROCESSING_FEE;
103	
104	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
105	  const { yearsWithMHPCO } = scenario.customer;
106	  const results = scenario.steps.map((step) => ({
107	    premium: roundUpToWhole(quotePremium(step.items, yearsWithMHPCO)),
108	  }));
109	  return { results };
110	};
